"""strings_agent_example.py — minimal prompt-assembly layer for a research agent."""
from __future__ import annotations
import json
import textwrap
from dataclasses import dataclass, field
from typing import Any


@dataclass
class ToolSpec:
    name: str
    description: str
    parameters: list[str]

    def to_text(self) -> str:
        """Human-readable one-liner for the system prompt tool list."""
        params = ", ".join(self.parameters)
        return f"  - {self.name}({params}): {self.description}"


class PromptBuilder:
    """Builds LLM API messages from typed parts."""

    def __init__(self, role: str, tools: list[ToolSpec]) -> None:
        tool_lines = "\n".join(t.to_text() for t in tools)
        self._system = textwrap.dedent(f"""\
            You are {role}.
            Available tools:
            {tool_lines}
            Call tools in JSON: {{"tool": "name", "input": ...}}
        """)

    def build_messages(self, query: str, context: str = "") -> list[dict[str, Any]]:
        user_parts = []
        if context.strip():
            user_parts.append(f"Context:\n{context.strip()}")
        user_parts.append(f"Question: {query}")
        user_content = "\n\n".join(user_parts)
        return [
            {"role": "system", "content": self._system},
            {"role": "user",   "content": user_content},
        ]

    def to_json(self, model: str, query: str, context: str = "") -> str:
        payload = {
            "model": model,
            "messages": self.build_messages(query, context),
        }
        return json.dumps(payload, ensure_ascii=False)


# ── Usage ─────────────────────────────────────────────────────────────────────
tools = [
    ToolSpec("search", "retrieve web documents", ["query", "top_k"]),
    ToolSpec("calc",   "evaluate math expression", ["expr"]),
]
builder = PromptBuilder("a research agent", tools)
